import{_ as e,o as a,c as r,a3 as l}from"./chunks/framework.BTFg6ESq.js";const f=JSON.parse('{"title":"云端 OCR 服务","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/ocr-service.md","filePath":"user-guide/settings/ocr-service.md","lastUpdated":1778244893000}'),o={name:"user-guide/settings/ocr-service.md"};function s(n,t,i,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="云端-ocr-服务" tabindex="-1">云端 OCR 服务 <a class="header-anchor" href="#云端-ocr-服务" aria-label="Permalink to &quot;云端 OCR 服务&quot;">​</a></h1><blockquote><p>如果你需要使用智能 OCR 工具的云端识别引擎，需要先在这里配置 OCR 服务渠道。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在左侧导航栏中选择 <strong>云端 OCR 服务</strong>。</li></ol><hr><h2 id="服务配置" tabindex="-1">服务配置 <a class="header-anchor" href="#服务配置" aria-label="Permalink to &quot;服务配置&quot;">​</a></h2><h3 id="标准服务商" tabindex="-1">标准服务商 <a class="header-anchor" href="#标准服务商" aria-label="Permalink to &quot;标准服务商&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>服务名称</strong></td><td style="text-align:left;">自定义名称</td></tr><tr><td style="text-align:left;"><strong>服务类型</strong></td><td style="text-align:left;">选择预设的 OCR 服务商（如百度云等）</td></tr><tr><td style="text-align:left;"><strong>API 端点</strong></td><td style="text-align:left;">服务地址</td></tr><tr><td style="text-align:left;"><strong>API Key / Secret</strong></td><td style="text-align:left;">认证凭据</td></tr></tbody></table><h3 id="自定义-api-支持" tabindex="-1">自定义 API 支持 <a class="header-anchor" href="#自定义-api-支持" aria-label="Permalink to &quot;自定义 API 支持&quot;">​</a></h3><p>如果标准服务商不满足需求，你可以配置<strong>自定义 API</strong>：</p><div> | 配置项 | 说明 | | :----------------- | :------------------------------ | | **自定义 API URL** | 请求目标地址 | | **HTTP 方法** | GET / POST 等 | | **请求头** | 自定义请求头 | | **请求体模板** | 支持 `{{imageBase64}}` 变量占位 | | **结果提取路径** | 从响应 JSON 中提取识别结果 | </div> --- <h2 id="性能与限制" tabindex="-1">性能与限制 <a class="header-anchor" href="#性能与限制" aria-label="Permalink to &quot;性能与限制&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>并发数</strong></td><td style="text-align:left;">1-10，控制图片块并行处理数</td></tr><tr><td style="text-align:left;"><strong>请求延迟</strong></td><td style="text-align:left;">0-5000ms，每次请求间的延时，避免触发限流</td></tr></tbody></table><blockquote><p>所有配置变更会在 1 秒防抖后<strong>自动保存</strong>。</p></blockquote><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-ocr-服务配置用于哪里" tabindex="-1">Q：OCR 服务配置用于哪里？ <a class="header-anchor" href="#q-ocr-服务配置用于哪里" aria-label="Permalink to &quot;Q：OCR 服务配置用于哪里？&quot;">​</a></h3><p>主要用于<strong>智能 OCR</strong> 工具的云端识别引擎。如果你只使用本地 OCR，则无需配置此项。</p>',20)])])}const u=e(o,[["render",s]]);export{f as __pageData,u as default};
